INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ペコリーヌが丹精込めて握った特大おにぎり。\nごはんは命のエネルギーを体現しているらしい。\n普通の人が満腹に感じる量の倍のサイズの中に\n最高級の具を閉じ込めた【美食殿】らしい一品。", 52001, 0, 2, 1, "500マイルを獲得する。", 1, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 1, "ペコリーヌの満腹ツインおにぎり", 0, 500, 1, 51001, 2, 10, "ペコリーヌの\n満腹ツインおにぎり");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("コッコロが皆のことを思って用意したサラダ。\n栄養バランスも考えられたうえに腹持ちもよく\n味だけではなく見た目にも気を配られている。\n冒険への活力を与えてくれる慈愛溢れる一品。", 52002, 0, 2, 3, "500マイルを獲得する。", 2, "このターンに振るダイスの目が必ず「1」になる。さらに、次のターン数のカウントをスキップする。", 1, "コッコロのゆるりと休憩サラダ", 0, 500, 1, 51002, 30001, 10, "コッコロの\nゆるりと休憩サラダ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("キャルが食べたい物を挟み込んだハンバーガー。\n香ばしいパンとお肉の香りが食欲を刺激する。\n魔物でない素材で作られた、冒険中に食べるには\nゴージャスすぎる一品、とキャルは信じている。", 52003, 0, 1, 2, "平凡な未鑑定トレジャーを1個獲得する。", 1, "このターンに振るダイスの目が必ず「5」になる。", 1, "キャルの絶品五つ星バーガー", 0, 500, 1, 51003, 20004, 10, "キャルの\n絶品五つ星バーガー");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("リリが作った柏餅……の中でも、上手く作れた\n選りすぐりの品。最高の素材を使用した上、\n失敗した分はリリが自分で食べてしまったため\n単価でみるとかなりの高級品となっている。", 52004, 0, 4, 2, "800マイルを獲得する。", 3, "ダイスを3回振るまでの間、ダイスの目が必ず「4」になる。", 1, "リリのコツコツまい進かしわ餅", 0, 500, 3, 51004, 20001, 10, "リリのコツコツ\nまい進かしわ餅");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("クリアが朝早くから用意した冒険用のお弁当。\nおかずは様々でどれも絶品だが、どんなものが\n入っているかはみんなにも秘密にされているため\n蓋を開けるまでのお楽しみとなっている。", 52005, 0, 1, 4, "次にダイスを振った際、1マス多く進める。", 3, "ランダムなイベントを発生させる。", 3, "クリアの彩り華やかバラエティ弁当", 0, 500, 0, 51005, 1, 11, "クリアの彩り華やか\nバラエティ弁当");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("プレシアが選び抜いた具を詰め込んだ肉まん。\n彼女の希望で、通常の肉まんの数倍のサイズに\nなっている。味もボリュームも満点でハッピー\n間違いなしですよ♪とは調理担当クリアの談。", 52006, 0, 4, 2, "800マイルを獲得する。", 1, "このターンに振るダイスの目が「4・5・6」のみになる。", 1, "プレシアの食いしん坊ぶーぶー肉まん", 0, 500, 1, 51006, 20002, 10, "プレシアの食いしん坊\nぶーぶー肉まん");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("カヤとイノリが弁当代わりに持ってきたケバブ。\nイノリ行きつけの店の硬派な味わいで、ギャング\nとしてのやる気が一人3倍、コンビで6倍となり\n下剋上を成し遂げるパワーが湧く……らしい。", 52007, 0, 3, 7, "福引券を1枚獲得する。", 1, "このターンに振るダイスの目を必ず「3」に、次のターンに振るダイスの目を必ず「6」にする。", 1, "カヤとイノリの食欲倍増ケバブサンド", 0, 500, 2, 51007, 1, 10, "カヤとイノリの\n食欲倍増ケバブサンド");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("タマキたちが『ジオ・テオゴニア』に持ち込んだ\nたい焼きの概念が現地の文化と溶け合い生まれた\n魔改造スイーツ。虹色に輝くその甘さは、実に\nランドソルのたい焼きの数倍と言われている。", 52008, 0, 2, 5, "500マイルを獲得する。", 2, "次にマイルマスに止まった際の獲得マイルが200%アップする。", 2, "タマキの金運招くレインボーたい焼き", 1, 500, 0, 51008, 200, 10, "タマキの金運招く\nレインボーたい焼き");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("クローチェがフルパワーで作ったポテトサラダ。\n本来はガレットを作ろうとしたが、うっかり\n握り潰してしまったため、軌道修正して仕上げ\nた一品。経緯はともかく味は非常に美味である。", 52009, 1, 1, 7, "平凡な未鑑定トレジャーを1個獲得する。", 2, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「8」に、次のターンに振るダイスの目を必ず「1」にする。", 1, "クローチェのフルパワーポテトサラダ", 0, 500, 2, 51009, 1, 10, "クローチェの\nフルパワーポテトサラダ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アヤネとクルミが二人で用意した特別なランチ\nバスケット。仲間との冒険への希望が詰まった\nご機嫌な料理の数々で、道中の様々な出来事が\n１ランク上のイベントに感じられるようになる。", 52010, 0, 2, 6, "500マイルを獲得する。", 3, "マップ上の「マイルマス」「トレジャーマス」 「ショップマス」のRANKが1つ上がる。効果は対象のマスに計2回止まるまで継続する。", 2, "アヤネとクルミの青空ピクニックセット", 2, 500, 0, 51010, 1, 10, "アヤネとクルミの\n青空ピクニックセット");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("リマがネネカにもらったリンゴで作った秘密の\nスイーツ。爽やかな酸味と濃厚な甘さがまるで\n魔法のようなバランスでお互いを引きたてており\n食べた者をたちまち虜にしてしまうという。", 52011, 0, 3, 7, "福引券を1枚獲得する。", 3, "このターンに振るダイスの目を必ず「2」に、次のターンに振るダイスの目を必ず「7」にする。", 1, "リマの不思議なスイートアップル", 0, 500, 2, 51011, 1, 10, "リマの不思議な\nスイートアップル");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ニノンがジオ・テオゴニアに持ち込んだ特別な\n寿司。厳選された新鮮な魚介を使った逸品だが、\n一部のネタは、寿司のセオリーを逸脱したニノン\n我流のものに仕上がっている。", 52012, 0, 1, 3, "平凡な未鑑定トレジャーを1個獲得する。", 2, "このターンに振るダイスの目が「1・2・3」のみになる。さらに、次のターン数のカウントをスキップする。", 1, "ニノンのオリジナル一二三寿司", 0, 500, 1, 51012, 30002, 10, "ニノンのオリジナル\n一二三寿司");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("クレジッタが考案した、ジオ・テオゴニアで流通\nしているチョコの貨幣の盛り合わせ。一見すると\n金貨を口に入れるおバカさんではあるが、通貨を\n食べるという背徳感が隠し味となっている。", 52013, 0, 4, 8, "800マイルを獲得する。", 3, "RANK2のマイルショップを開く。", 3, "クレジッタの開運お菓子盛り合わせ", 0, 500, 0, 51013, 2, 10, "クレジッタの開運\nお菓子盛り合わせ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("可愛い妹がお兄ちゃんのために心を込めて作った\nスペシャルなかき氷。一口食べるとたちどころに\nクールな甘さが精神を研ぎ澄まし、いかなる\nお得をも見逃さない要塞賢母と化すという。", 52014, 0, 1, 9, "次にダイスを振った際、1マス多く進める。", 2, "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", 1, "リノの「時は金時」かき氷", 0, 500, 2, 51014, 1, 11, "リノの\n「時は金時」かき氷");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("お姉ちゃんが弟くんのために心を込めて作った\nスペシャルなハンバーグ。アツアツの肉汁と共に\n溢れんばかりの愛が詰まっており、一口食べる\nだけで、走り回りたくなるような美味しさ。", 52015, 0, 1, 1, "次にダイスを振った際、1マス多く進める。", 1, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 1, "シズルの愛情盛り盛りハンバーグ", 0, 500, 1, 51015, 2, 11, "シズルの愛情\n盛り盛りハンバーグ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アオイがお弁当として作ったエルフ伝統の野菜\nサンド。一緒についてきてくれる最高の友だち\nの助言により、どんなに深い森の中でも全速力\nで駆け抜けることができるらしい。（アオイ談）", 52016, 0, 0, 2, "なし", 3, "このターンに振るダイスの目が必ず「6」になる。", 1, "アオイの疾走サンドイッチ", 0, 500, 1, 51016, 20005, 0, "アオイの疾走\nサンドイッチ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("数多くのドM妄想をしてきたクウカの中で最近の\nマイブームである触手をモチーフとした活造り。\n新鮮な蛸足が、濃厚なうま味と共に物理的に絡み\n付き身も心も縛りあげられる様な体験ができる。", 52017, 1, 5, 2, "なし", 3, "[FF7C4E,D62146]【上書き不可】[-]次のターン「移動系カテゴリーの料理」が食べられない代わりに、その場で2000マイルを獲得する。", 1, "クウカの緊縛触手活け造り", 0, 500, 2, 51017, 1, 10, "クウカの緊縛\n触手活け造り");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("コッコロの指導により料理の腕を上げたランファ\nが手作りした肉じゃが。まだ改善の余地はある\nものの、不器用なランファが誰かのために積み\n重ねた努力を思うととてもおいしく味わえる。", 52018, 0, 6, 2, "1000マイルを獲得する。", 1, "このターンに振るダイスの目が必ず「3」になる。", 1, "ランファの世話焼き三昧肉じゃが", 0, 500, 1, 51018, 20006, 10, "ランファの世話焼き三昧肉じゃが");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("バンディ・シスターズの昨夜の夕食カレー。作り\n過ぎて食べきれずにいたものをワカナがお裾分け\nしてくれた。寝かされていたためしっかりと味の\n染みた、極上の二日目カレーとなっている。", 52019, 0, 0, 2, "なし", 1, "このターンに振るダイスの目が必ず「8」になる。", 1, "ワカナの節約腹八分目カレー", 0, 500, 1, 0, 20007, 0, "ワカナの節約腹八分目カレー");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("可愛い妹がお兄ちゃんのために心を込めて作った\nスペシャルなかき氷。一口食べるとたちどころに\nクールな甘さが精神を研ぎ澄まし、いかなる\nお得をも見逃さない要塞賢母と化すという。", 52020, 0, 1, 9, "次にダイスを振った際、1マス多く進める。", 2, "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", 2, "リノの「時は金時」かき氷", 0, 500, 2, 51014, 1, 11, "リノの\n「時は金時」かき氷");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("綺麗な装飾箱に納められたボンボン・ショコラ。\nそのほろ苦さを秘めた濃密な甘さが灰色の脳細胞\nに働きかける時、名探偵の鋭い推理が隠された\n謎を全て白日の下へと晒し、事件を解決へ導く。", 52021, 0, 7, 9, "	平凡な未鑑定トレジャーを2個獲得する。", 3, "トレジャーマスをスキップして移動できる。効果は3ターンの間継続する。", 2, "カスミの真実見抜くボンボン・ショコラ", 0, 500, 3, 51021, 2, 10, "カスミの真実見抜く\nボンボン・ショコラ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アキノがジオ・ゲヘナで仕入れてきたスパイスを\n使用した、お洒落で豪華なチキンプレート。牧場\n特製ヨーグルトソースと奏でる刺激的な味わいは\nまさに二つの世界の奇跡のマリアージュである。", 52022, 0, 0, 2, "なし", 1, "ダイスを3回振るまでの間、「5と6」の⽬が出る確率が3倍になる。", 1, "アキノのゲヘニアンチキンプレート", 0, 500, 3, 51022, 20008, 0, "アキノのゲヘニアン\nチキンプレート");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ミミが、ジオ・ゲヘナで助けてくれたお姉さん達\nのことを思い作ったおにぎり。それぞれ異なる\n味付けがされているが、ミミの願い通りお互いに\nケンカをせず仲良くハーモニーを奏でている。", 52023, 1, 1, 7, "平凡な未鑑定トレジャーを1個獲得する。", 1, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「6」に、次のターンに振るダイスの目を必ず「3」にする。", 1, "ミミのコロコロお手玉おにぎり", 0, 500, 2, 51023, 1, 10, "ミミのコロコロ\nお手玉おにぎり");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("気が付くとリリの手元にあった不思議なお菓子。\n一見普通のケーキだが、内部に様々な具材が\n隠れるように入っている。複雑で重層的な\n味わいを見せる様は、まるで誰かさんのよう。", 52024, 0, 3, 8, "次にダイスを振った際、3マス多く進める。", 3, "RANK2のマイルショップを開く。", 3, "アユミの隠密ガトーインビジブル", 0, 500, 0, 51024, 2, 11, "アユミの隠密\nガトーインビジブル");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アネモネが世話する秘密の菜園の野菜を使った\nサラダ。栄養を重視するアネモネは草食獣の肉を\n野菜と解釈、当初は野菜の上に肉を置いただけ\nであったが、ネラの指導で盛り付け直された。", 52025, 0, 0, 9, "なし", 3, "「マイルマス」「トレジャーマス」をスキップして移動できる。効果は1ターンの間継続する。", 2, "アネモネの花爛漫ステーキサラダ", 0, 500, 1, 51025, 3, 0, "アネモネの\n花爛漫ステーキサラダ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ジオ・ゲヘナを探索中の冥姫たちが現地で採取\nしたスパイスで味付けした一皿。赤く煮え滾る\nソースは刺激的かつ非常に奥深い味わいで未知の\n大地の如く冒険者たちをその深奥へと誘う。", 52026, 0, 8, 4, "福引券を2枚獲得する。", 1, "ランダムなイベントを発生させる。", 3, "アンナの煉獄蕃茄煮混沌卵", 0, 500, 0, 51026, 1, 10, "アンナの\n煉獄蕃茄煮混沌卵");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ユイが食べる人のことを考え、心を込めて作った\nお弁当。程よいサイズのお弁当箱に愛情と手間暇\nをたっぷりとかけた極上の料理が詰まっており、\n食べた者の心と胃袋を優しく満たしてくれる。", 52027, 0, 0, 2, "なし", 3, "ダイスを2回振るまでの間、ダイスの目が必ず「5」になる。", 1, "ユイの栄養満点まごころ弁当", 0, 500, 2, 51027, 20004, 0, "ユイの\n栄養満点まごころ弁当");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("リンからもらった非常食のあんパン。ナッツが\n練り込まれクランチな食感で食べ飽きない。\nゲームのため部屋に引きこもる際のお供であり、\n必要な栄養素が全て賄える完全栄養食、らしい。", 52028, 0, 9, 2, "なし", 3, "このターンに振るダイスの目が「1・2」のみに\nなる代わりに、その場で福引券を3枚獲得する。", 1, "リンのナッツ入りぐうたらあんパン", 0, 500, 1, 51028, 30003, 10, "リンの\nナッツ入りぐうたらあんパン");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("シェフィが自身の魔力の氷を使い作ったアイス。\nペコリーヌにねだられて作ったものだがキャル達\nにも好評である。コッコロ曰くひんやりしている\nのに食べると心が温かくなってきます、との事。", 52029, 0, 0, 3, "なし", 2, "このターンに振るダイスの目が必ず「2」になる。さらに、次のターン数のカウントをスキップする。", 1, "シェフィの氷晶煌めく手作りアイス", 0, 500, 1, 51029, 30004, 0, "シェフィの\n氷晶煌めく手作りアイス");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ミソラが作ったラーメン。適当に言った好きな物\nをランファが憶えていたために、材料を用意され\n仕方なく作ったものだが味はイイコト級の一品。\n美味しそうに食べられるのは嫌いではない様子。", 52030, 0, 0, 12, "なし", 1, "3ターンの間、すべての「マイルマス」をランク3の「トレジャーマス」に変化させる。", 3, "ミソラの気まぐれ味噌ラーメン★", 0, 500, 3, 51030, 1, 0, "ミソラの\n気まぐれ味噌ラーメン★");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("イロハがいつも持ち歩いているカラフルなゼリー\n…なのだがアルケス錬金堂で作られたクワガタ用\n餌ゼリーとそっくりな見た目をしている。甘くて\n美味しいが、人間用か尋ねると目を逸らされる。", 52031, 0, 0, 2, "なし", 3, "このターンに振るダイスの目が「1・6・6・6・8・8」になる。", 1, "イロハの最強クワガタゼリー（人間用）", 0, 500, 1, 51031, 20009, 0, "イロハの\n最強クワガタゼリー（人間用）");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("グレイスお手製のカップケーキ。ショッキングな\n見た目に全振り…と思わせて目玉も食べることが\n可能で大変美味…と思わせて一部だけ魂消るほど\n甘い部分がある。原材料は頑なに秘されている。", 52032, 0, 3, 9, "次にダイスを振った際、3マス多く進める。", 3, "料理マスをスキップして移動できる。効果は2ターンの間継続する。", 2, "グレイスの目ん玉飛び出るカップケーキ", 0, 500, 2, 51032, 4, 11, "グレイスの\n目ん玉飛び出るカップケーキ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ソノが作ったオムライス。イロハの大好物であり\n家庭の味。普段は面倒くさがりやらないがイロハ\nが良い子の時はケチャップでクワガタを描いて\nあげている。その時は普段より美味しいらしい。", 52033, 0, 0, 8, "なし", 1, "RANK3のマイルショップを開く。", 3, "ソノの今日は特別ご褒美オムライス", 0, 500, 0, 51033, 3, 0, "ソノの今日は特別ご褒美オムライス");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("そのあまりの美味さと、ほとばしるカロリーから\n悪意の塊、という物騒な名が付けられた肉料理。\nこの肉を集められるかが騎空士としての力量を\n示すため、ジータは大量に集めたがっている。", 52034, 0, 1, 9, "平凡な未鑑定トレジャーを1個獲得する。", 1, "マイルマスをスキップして移動できる。効果は2ターンの間継続する。", 2, "ジータのグリルド・グラッジチャンク", 0, 500, 2, 51034, 1, 10, "ジータの\nグリルド・グラッジチャンク");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ルイズマリーが祖母のレシピを忠実に再現した\n最高傑作。精緻な調合と温度管理が生み出す衣と\n身のサクフワは錬金技術の到達点と言われている\nが、ただの料理なのではとの意見も絶えない。", 52035, 0, 10, 4, "貴重な未鑑定トレジャーを1個獲得する。", 1, "ランダムなイベントを発生させる。", 3, "ルイズマリーの成功しすぎてるフライ", 0, 500, 0, 51035, 1, 10, "ルイズマリーの\n成功しすぎてるフライ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ジオ・ゲヘナの空の覇者にして煉華のホウオウが\n己への信仰心を集めるべく作らせたお菓子。中の\n餡はしっとり甘く、上品な味わい。ジオ・ゲヘナ\n銘菓の名を恣にする日も近い、かもしれない。", 52036, 1, 0, 7, "なし", 3, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「12」に、次とさらにその次のターンに振るダイスの目を必ず「1」にする。", 1, "ホウオウの食べる権利をあげます！饅頭", 0, 500, 3, 51036, 1, 0, "ホウオウの\n食べる権利をあげます！饅頭");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ナナカ考案＆監修のウエハース。おまけシールの\nコレクション性を高くした結果ランドソル中で\n大ブーム…だが肝心の菓子が棄てられる事態に。\n解決のため、王女が自ら口を開いたのだった。", 52037, 0, 11, 6, "平凡な未鑑定トレジャーを3個獲得する。", 3, "マップ上の「マイルマス」「トレジャーマス」 「ショップマス」のRANKが1つ上がる。効果は対象のマスに計1回止まるまで継続する。", 2, "魔法少女ナナカちゃんウエハース", 1, 500, 0, 51037, 1, 10, "魔法少女\nナナカちゃんウエハース");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アリサ特製の包み焼き。伝承の怪物とよく似た\n魔物を材料にしているため、いつしかその怪物と\n同じ名で呼ばれるようになったという。鋭い鎌と\n火傷に気を付けながら、熱々を召し上がれ。", 52038, 0, 3, 1, "福引券を1枚獲得する。", 1, "次に振るダイスが2個に増える。出目の合計の数だけ進める。", 1, "アリサがお届け♪リノセウスの包み焼き", 0, 500, 1, 51038, 2, 10, "アリサがお届け♪\nリノセウスの包み焼き");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("イリヤの愛飲する赤く鮮やかなトマトジュース。\n伝説の吸血鬼に相応しいクオリティを、と求めた\n末に辿り着いた究極の逸品。しかしお値段も相応\nに張るため、特別な時にしか飲めないらしい。", 52039, 0, 0, 12, "なし", 2, "2ターンの間、すべての「マイルマス」をランク3の「ショップマス」に変化させる。", 3, "イリヤの†ブラッディ†トマトジュース", 0, 500, 2, 51039, 2, 0, "イリヤの†ブラッディ†\nトマトジュース");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("【王宮騎士団】遠征時の定番メニューにマツリが\nアレンジを加え調理したプレート。苦手な野菜を\nなくしてお肉倍増を目論んだのが配膳前にバレ、\nジュンの指導できちんと野菜も入れさせられた。", 52040, 0, 2, 9, "次にダイスを振った際、2マス多く進める。", 1, "トレジャーマスをスキップして移動できる。効果は3ターンの間継続する。", 2, "マツリの活力源～騎士団遠征プレート～", 0, 500, 3, 51040, 2, 11, "マツリの活力源\n～騎士団遠征プレート～");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ヴァンピィがよく振舞ってくれる特製スープ。\nどうやら家庭料理のようで、素朴な味わいが\n人々を郷愁へと誘う。昔誰かと並んで一緒に\n肉団子を作ったような…とはヴァンピィの言葉。", 52041, 1, 1, 7, "平凡な未鑑定トレジャーを1個獲得する。", 1, "[FF7C4E,D62146]【上書き不可】[-]このターンに振るダイスの目を必ず「7」に、次のターンに振るダイスの目を必ず「2」にする。", 1, "ヴァンピィちゃんのさいきょースープ", 0, 500, 2, 51041, 1, 10, "ヴァンピィちゃんの\nさいきょースープ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アイラが愛する赤麦しゅわ。彼女の熱い要望で\n酩酊感ゼロの子供向けも生産開始した。曰くこの\n美味しさを広めるためとのことだが、本当は単に\n老若男女皆で楽しく飲みたいだけかもしれない。", 52042, 0, 0, 2, "なし", 2, "ダイスを2回振るまでの間、出る目が「4・5・6」のみになる", 1, "アイラのみんなで飲みたい赤麦しゅわ", 0, 500, 2, 51042, 20002, 0, "アイラのみんなで\n飲みたい赤麦しゅわ");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("レイが釣った魚の塩焼き。試行錯誤の末に理想の\n塩と火の加減にたどり着いた。調理は真剣勝負で\n釣りと同様、己の心との戦いだという。レイも\n時々、集中しすぎて仲間に心配されているとか。", 52043, 1, 12, 2, "なし", 1, "[FF7C4E,D62146]【上書き不可】[-]次のターン「移動系カテゴリーの料理」が食べられない代わりに、その場で貴重な未鑑定トレジャーを3個獲得する。", 1, "レイの釣りたて鮮魚七輪塩焼き", 0, 500, 2, 51043, 1, 10, "レイの釣りたて\n鮮魚七輪塩焼き");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("ユキノが偶然生み出した、青果実のアイスバー。\n元は誤って凍らせたものだが爽やかな味が好評で\nなんと久遠氷河を代表する手土産に。伸び続ける\n売り上げに本人が一番溶けそうになっている。", 52044, 0, 3, 3, "福引券を1枚獲得する。", 2, "このターンに振るダイスの目が「1・2・3」のみになる。さらに、次のターン数のカウントをスキップする。", 1, "ユキノ製ごろっと果実のかちこち氷菓子", 0, 500, 1, 51044, 30002, 10, "ユキノ製ごろっと果実の\nかちこち氷菓子");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("サレンが作った思い出の焼きそばパン。どっしり\nしたボリュームある炭水化物×炭水化物の信頼感\nで皆を笑顔に変える。専用の皿に盛り付けたら見\n栄えも十分。カロリーは気にしないのがお作法。", 52045, 0, 4, 9, "800マイルを獲得する。", 3, "「ショップマス」「ミニゲームマス」「イベントマス」をスキップして移動できる。効果は3ターンの間継続する。", 2, "サレンの思い出ぎっしり焼きそばパン", 0, 500, 3, 51045, 5, 10, "サレンの思い出ぎっしり\n焼きそばパン");
INSERT INTO `v1_f59bb358cc0c11277e36025f29c1dddbc5d09cad39d35e0eb0b0ece8f34ab5fc` VALUES ("アラクネが初めて覚えた料理。周囲の人々が自分\nより小さいのは小食が理由と思っているらしく、\nたくさん食べて大きくなってほしいという優しさ\nから、超ボリュームなデカ盛り仕様となった。", 52046, 0, 0, 9, "なし", 1, "マイルマスをスキップして移動できる。効果は3ターンの間継続する。", 2, "アラクネの肉マシマシマシ炒め野菜入り", 0, 500, 3, 51046, 1, 0, "アラクネの肉マシマシマシ炒め\n野菜入り");
